1911 void Verifier::visitModuleFlags() {
1912   const NamedMDNode *Flags = M.getModuleFlagsMetadata();
1913   if (!Flags) return;
1914 
1915   // Scan each flag, and track the flags and requirements.
1916   DenseMap<const MDString*, const MDNode*> SeenIDs;
1917   SmallVector<const MDNode*, 16> Requirements;
1918   uint64_t PAuthABIPlatform = -1;
1919   uint64_t PAuthABIVersion = -1;
1920   for (const MDNode *MDN : Flags->operands()) {
1921     visitModuleFlag(MDN, SeenIDs, Requirements);
1922     if (MDN->getNumOperands() != 3)
1923       continue;
1924     if (const auto *FlagName = dyn_cast_or_null<MDString>(MDN->getOperand(1))) {
1925       if (FlagName->getString() == "aarch64-elf-pauthabi-platform") {
1926         if (const auto *PAP =
1927                 mdconst::dyn_extract_or_null<ConstantInt>(MDN->getOperand(2)))
1928           PAuthABIPlatform = PAP->getZExtValue();
1929       } else if (FlagName->getString() == "aarch64-elf-pauthabi-version") {
1930         if (const auto *PAV =
1931                 mdconst::dyn_extract_or_null<ConstantInt>(MDN->getOperand(2)))
1932           PAuthABIVersion = PAV->getZExtValue();
1933       }
1934     }
1935   }
1936 
1937   if ((PAuthABIPlatform == uint64_t(-1)) != (PAuthABIVersion == uint64_t(-1)))
1938     CheckFailed("either both or no 'aarch64-elf-pauthabi-platform' and "
1939                 "'aarch64-elf-pauthabi-version' module flags must be present");
1940 
1941   // Validate that the requirements in the module are valid.
1942   for (const MDNode *Requirement : Requirements) {
1943     const MDString *Flag = cast<MDString>(Requirement->getOperand(0));
1944     const Metadata *ReqValue = Requirement->getOperand(1);
1945 
1946     const MDNode *Op = SeenIDs.lookup(Flag);
1947     if (!Op) {
1948       CheckFailed("invalid requirement on flag, flag is not present in module",
1949                   Flag);
1950       continue;
1951     }
1952 
1953     if (Op->getOperand(2) != ReqValue) {
1954       CheckFailed(("invalid requirement on flag, "
1955                    "flag does not have the required value"),
1956                   Flag);
1957       continue;
1958     }
1959   }
1960 }
1961 
1962 void
1963 Verifier::visitModuleFlag(const MDNode *Op,
1964                           DenseMap<const MDString *, const MDNode *> &SeenIDs,
1965                           SmallVectorImpl<const MDNode *> &Requirements) {
1966   // Each module flag should have three arguments, the merge behavior (a
1967   // constant int), the flag ID (an MDString), and the value.
1968   Check(Op->getNumOperands() == 3,
1969         "incorrect number of operands in module flag", Op);
